import { getServices } from "@/lib/fetchers";
import Container from "@/components/ui/Container";
import Link from "next/link";
import Image from "next/image";
import type { Metadata } from "next";
import { Button } from "@/components/ui/Button";
import BreadcrumbSection from "@/components/ui/BreadcrumbSection";
import FaqSection from "@/components/sections/FaqSection";

export const metadata: Metadata = {
  title: "Services",
  description:
    "Discover our range of digital marketing and social media services.",
};

export const revalidate = 60;

const DUMMY_SERVICES = [
  {
    id: "1",
    title: "Search Engine Optimization",
    slug: "seo",
    description:
      "Boost your rankings and drive organic traffic with our expert SEO strategies.",
    image: "https://picsum.photos/seed/seo/800/800",
  },
];


export default async function ServicesPage() {
  const servicesFromDB = await getPublishedServices();

  const services =
    servicesFromDB && servicesFromDB.length > 0
      ? servicesFromDB
      : DUMMY_SERVICES;

  return (
    <div>
      <BreadcrumbSection
        title="Services"
        items={[{ label: "Home", href: "/" }, { label: "Services" }]}
      />

      <Container className="py-24">

        {/* Heading */}
        <div className="max-w-2xl mb-20 space-y-4">
          <h1 className="text-4xl md:text-5xl font-bold tracking-tight">
            Our Services
          </h1>
          <p className="text-xl text-slate-600">
            Powerful digital solutions tailored to elevate your brand.
          </p>
        </div>

        {/* Services List */}
        <div className="space-y-32">
          {services.map((service: any, index: number) => (
            <div
              key={service.id}
              className={`flex flex-col lg:items-center gap-12 lg:gap-24 ${
                index % 2 === 1
                  ? "lg:flex-row-reverse"
                  : "lg:flex-row"
              }`}
            >
              {/* Text Section (20% Icon style layout inside) */}
              <div className="flex-1 space-y-8">

                {/* Number Badge */}
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-indigo-100 text-indigo-600 text-2xl font-bold">
                  {index + 1}
                </div>

                <h2 className="text-3xl md:text-4xl font-bold">
                  {service.title}
                </h2>

                <p className="text-lg text-slate-600 leading-relaxed">
                  {service.description}
                </p>

                <Link
                  href={`/services/${service.slug}`}
                  className="inline-flex items-center text-indigo-600 font-semibold hover:underline"
                >
                  Learn More →
                </Link>
              </div>

              {/* Image Section */}
              <div className="flex-1 relative aspect-video lg:aspect-square rounded-3xl overflow-hidden shadow-xl">
                <Image
                  src={
                    service.image ||
                    `https://picsum.photos/seed/${service.slug}/800/800`
                  }
                  alt={service.title}
                  fill
                  className="object-cover"
                  sizes="(max-width:1024px) 100vw, 50vw"
                  priority={index === 0}
                />
              </div>
            </div>
          ))}
        </div>
      </Container>
    </div>
  );
}

<FaqSection />